export const QUESTIONS = [{"id":"0RPUbg27qugYEHBASYED","type":"subjective","question":"Animals that are hunted and killed by other animals for food are referred to as ____.","options":null,"answerIndex":null,"answer":"prey","explanation":["Prey refers to the target animals captured and eaten by predators."],"hint":"This term sounds like a word used when asking or wishing for something, but spelled differently.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"0itK3SPrAsNHXMEXAoqI","type":"objective","question":"If a disease kills off a huge number of primary consumers in a savanna, which group will suffer next?","options":["Producers","Secondary consumers","Decomposers exclusively","Algae"],"answerIndex":1,"answer":null,"explanation":["Secondary consumers rely directly on primary consumers for food; their food supply would instantly crash."],"hint":"Think about who directly hunts and eats primary consumers.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"10VDlx8NxwBkqXMX75P9","type":"polar","question":"An ecosystem can support a larger population of apex predators than it can of green plants.","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["Because energy is lost at each step up a food chain, there must always be far more producers than top predators."],"hint":"Think about the energy pyramid. Is there more energy at the top or at the bottom?","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"1kUsy1HdqhLG9NoHdcJP","type":"subjective","question":"When a plant captures sunlight to create sugar, it changes light energy into ____ energy.","options":null,"answerIndex":null,"answer":"chemical","explanation":["Photosynthesis converts radiant solar energy into stored chemical energy in glucose."],"hint":"This is the form of energy stored inside bonds of food molecules.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"4liJdS217X2Po0qVG8Ae","type":"short","question":"If all the green plants were removed from an ecosystem, what would happen to the herbivores?","options":null,"answerIndex":null,"answer":"They would die or move away","explanation":["Herbivores depend entirely on producers for nutrition; without them, starvation occurs."],"hint":"Think about what herbivores rely on entirely for food.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"57och4IPF5Fe9jIRS4Em","type":"theory","question":"If a farmer sprays chemical pesticides that eliminate all insects in a pasture, explain how insect-eating birds could be impacted.","options":null,"answerIndex":null,"answer":"The insect-eating birds would lose their primary source of food. They would either face starvation, experience drops in population, or be forced to migrate to another area to look for insects.","explanation":["Removing a central link in a food web drastically impacts the consumers above it."],"hint":"","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"7zVyvGknqfgheUiRS6yA","type":"theory","question":"Distinguish between a primary consumer and a secondary consumer using examples.","options":null,"answerIndex":null,"answer":"A primary consumer eats producers directly, like a rabbit eating grass. A secondary consumer eats primary consumers, like a fox eating the rabbit.","explanation":["Primary consumers are herbivores, whereas secondary consumers are typically carnivores or omnivores."],"hint":"","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"90sYZaEQuE8QsV9oW1dz","type":"polar","question":"Fungi can produce their own food when there is absolutely no sunlight available.","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["Fungi are not plants and cannot photosynthesize; they absorb nutrients from decaying organic matter."],"hint":"Are fungi plants or do they absorb nutrients from dead material?","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"A37ZyVTJ9jXm2FYHY1E5","type":"subjective","question":"A network of interconnected food chains showing all feeding relationships in an ecosystem is called a food ____.","options":null,"answerIndex":null,"answer":"web","explanation":["A food web is an overlapping network of multiple food chains inside a shared habitat."],"hint":"Think of a structure spun by a spider that connects many lines together.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"GZfmLz7wxF6bKKmkAHTA","type":"objective","question":"Which of these pairs represents two decomposers?","options":["Earthworm and Rabbit","Fern and Moss","Bacteria and Mushroom","Eagle and Snake"],"answerIndex":2,"answer":null,"explanation":["Bacteria and mushrooms (fungi) are classic examples of saprophytic decomposers."],"hint":"Look for microscopic organisms or fungi that break down decaying material.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"HK0E0vzevaTlBcK4lvwp","type":"subjective","question":"Organisms like mushrooms and bacteria that break down dead material and return nutrients to the soil are called ____.","options":null,"answerIndex":null,"answer":"decomposers","explanation":["Decomposers break down dead or decaying organisms, completing the nutrient cycle."],"hint":"Think about the process of rotting or decomposing.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"I1dXz1kaIxx3IXlZMYcf","type":"theory","question":"Why can an animal be part of more than one food chain at the same time?","options":null,"answerIndex":null,"answer":"Most animals do not eat just one type of food. An animal might eat different types of prey or plants, placing it into multiple intersecting food chains, which forms a food web.","explanation":["Ecosystems are complex webs rather than single linear paths because organisms have varied diets."],"hint":"","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"J6hn8Wy11AihUPWwsjf9","type":"theory","question":"Why do we say that humans are omnivores? Support your answer with common dietary examples.","options":null,"answerIndex":null,"answer":"Humans are omnivores because their diet normally includes both plant matter (like vegetables, fruits, and grains) and animal matter (like chicken, fish, beef, or eggs).","explanation":["Diets containing both primary producer products and animal tissues define an omnivorous organism."],"hint":"","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"Jovh55RaiBXZCsHDLag5","type":"objective","question":"In an ocean food chain where microscopic algae are eaten by krill, and krill are eaten by a blue whale, which organism is the producer?","options":["Microscopic algae","Krill","Blue whale","The water"],"answerIndex":0,"answer":null,"explanation":["Algae are photosynthetic organisms that serve as the foundation or producer level in aquatic food chains."],"hint":"Look for the organism that performs photosynthesis in the water.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"Lsbkqvm4xDHB0CiJUE3t","type":"theory","question":"What is a major difference between a scavenger and a decomposer?","options":null,"answerIndex":null,"answer":"A scavenger is an animal that eats large pieces of dead organic matter (like a vulture eating a carcass). A decomposer breaks down the remaining microscopic organic matter completely into nutrients that return to the soil (like bacteria or fungi).","explanation":["Scavengers consume organic remains mechanically, while decomposers perform chemical breakdown at a molecular level."],"hint":"","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"TkuQiOaQ8jckhRFdLoFQ","type":"subjective","question":"The positions or steps that organisms occupy within a food chain are called ____ levels.","options":null,"answerIndex":null,"answer":"trophic","explanation":["Trophic levels define the hierarchical steps of an organism's feeding status in a food chain."],"hint":"This scientific word comes from a Greek word related to feeding or nourishment.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"UMrCul2M2jofps26Maer","type":"polar","question":"Decomposers are not important to producers because plants only need sunlight to grow.","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["Decomposers recycle vital mineral nutrients back into the soil, which plants require for healthy growth."],"hint":"Think about where plants get their soil nutrients from.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"V4KZYgM3NkuL7Iin5HKf","type":"polar","question":"An animal can be both a predator and a prey at the same time in an ecosystem.","options":["True","False"],"answerIndex":0,"answer":null,"explanation":["Many mid-level consumers act as predators to smaller animals while being preyed upon by apex predators."],"hint":"Think of a frog that hunts insects but gets eaten by a snake.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"VNynnITAD9NJMsmlhagk","type":"objective","question":"If a grasshopper eats grass, and a frog eats the grasshopper, what role does the frog play?","options":["Producer","Primary consumer","Secondary consumer","Decomposer"],"answerIndex":2,"answer":null,"explanation":["The grass is the producer, the grasshopper is the primary consumer, and the frog is the secondary consumer."],"hint":"Count the steps away from the producer (grass).","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"WatJmbY6kwW3u7tdWeE2","type":"short","question":"What term is used for an animal, like a grizzly bear or a human, that eats both plants and animals?","options":null,"answerIndex":null,"answer":"Omnivore","explanation":["Omnivores consume both plant matter and meat from other animals."],"hint":"This word means eating 'all' or multiple types of food sources.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"Wc8ZKhQsdnEzHgsVWd8J","type":"polar","question":"In a food chain, the arrows point towards the organism that is being eaten.","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["Arrows in a food chain point to the consumer to show the transfer of energy, not the organism being eaten."],"hint":"Think about the direction of the flow of energy.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"XFWZLjGpXM8c6XAWRSHd","type":"polar","question":"Carnivores are organisms that get their energy directly from manufacturing glucose via sunlight.","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["Carnivores get energy by eating other animals, not from sunlight directly."],"hint":"Do carnivores eat plants or other animals?","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"XY0rruQUiUBazMZ88YRy","type":"short","question":"What basic gas do plants absorb from the air to perform photosynthesis and build their biomass?","options":null,"answerIndex":null,"answer":"Carbon dioxide","explanation":["Plants use carbon dioxide along with water and sunlight to synthesize sugars."],"hint":"It is the gas that humans breathe out as waste.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"YLzHxAuchcLvaqHf4SSM","type":"short","question":"What scientific term describes an animal that feeds exclusively on plants?","options":null,"answerIndex":null,"answer":"Herbivore","explanation":["Herbivores are primary consumers that eat only plants or algae."],"hint":"Think of words ending in '-vore' that deal with vegetation.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"ZPKAqVU9zCPp0HYRuRka","type":"subjective","question":"A caterpillar eating a plant leaf is an example of a relationship between a producer and a ____ consumer.","options":null,"answerIndex":null,"answer":"primary","explanation":["Primary consumers are the first organisms to eat the producers in any food chain."],"hint":"This is the first level of consumer in a chain.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"ZvSN4pUy29LfWIxgGvg5","type":"objective","question":"Look at this written sequence: Grass -> Slug -> Thrush -> Hawk. Which organism receives energy directly from the slug?","options":["Grass","Thrush","Hawk","The Sun"],"answerIndex":1,"answer":null,"explanation":["The arrow points from the slug to the thrush, meaning the thrush consumes the slug and gets its energy."],"hint":"Look at which organism is immediately to the right of the slug.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"ZzKFq174Y5D26rRZBGBz","type":"short","question":"What is the term for a flesh-eating animal that only eats meat?","options":null,"answerIndex":null,"answer":"Carnivore","explanation":["Carnivores are consumers that strictly eat other animals."],"hint":"Lions, wolves, and hawks belong to this group.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"aT0WhgXkXkXcrtHUshqY","type":"theory","question":"Why is energy lost as it moves up from one level of a food chain to the next?","options":null,"answerIndex":null,"answer":"Energy is lost because organisms use it up for everyday life processes like moving, growing, and staying warm. Some energy is also lost as heat to the environment.","explanation":["Only about 10 percent of energy is passed to the next level because of metabolic usage and heat dissipation."],"hint":"","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"bQmSRpP2vAghEvjOuPeC","type":"short","question":"In a food web containing grass, grasshoppers, sparrows, and hawks, which animal is the apex predator?","options":null,"answerIndex":null,"answer":"Hawk","explanation":["The hawk occupies the highest level here and is not preyed upon by any other animals in this list."],"hint":"Look for the bird of prey at the very end of the consumption paths.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"gDne9yYTyQ27W4Y80Lvl","type":"short","question":"What type of organism is always found at the very beginning of a food chain?","options":null,"answerIndex":null,"answer":"Producer","explanation":["Every food chain must start with a producer that converts ambient energy into food material."],"hint":"This group can create its own organic energy matter.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"io6Ijkwc1CLvSfzRWlea","type":"subjective","question":"An organism that hunts, catches, and eats another animal for food is called a ____.","options":null,"answerIndex":null,"answer":"predator","explanation":["A predator is an animal that naturally preys on others for sustenance."],"hint":"This is the opposite role of the prey in an ecosystem.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"j5ZSHhch8NeTxJoMRNpE","type":"objective","question":"What is the primary source of energy that kicks off almost every food chain on Earth?","options":["Water","The Sun","Soil nutrients","Oxygen"],"answerIndex":1,"answer":null,"explanation":["The Sun provides the initial light energy captured by producers to initiate energy flow in an ecosystem."],"hint":"Think about what green plants need to capture to make their own food.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"oJ3joItMaBHAOJ0vIZng","type":"theory","question":"Explain what would happen to a population of owls if the population of mice (their main food source) suddenly decreased.","options":null,"answerIndex":null,"answer":"The population of owls would likely decrease as well. With less food available, some owls might starve, reproduce less successfully, or move away to find food elsewhere.","explanation":["Consumers depend directly or indirectly on other levels; a drop in prey limits predator survival."],"hint":"","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"ogFKzJZUejffivD30wqU","type":"objective","question":"Which of these organisms represents a consumer in a backyard ecosystem?","options":["Grass","An oak tree","A caterpillar","A rose bush"],"answerIndex":2,"answer":null,"explanation":["Caterpillars are animals that must consume plant tissue to survive, making them consumers."],"hint":"Look for the organism that must eat something else to get energy.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"p9AcOVfDKjJMaVAhBAKw","type":"theory","question":"An apex predator sits at the top of a food chain. What does this mean regarding its natural predators?","options":null,"answerIndex":null,"answer":"An apex predator has no natural predators within its ecosystem. It is not hunted or eaten by any other animals while it is alive.","explanation":["Apex predators reside at the highest trophic level of their local food chain or web."],"hint":"","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"pC1wqoWGiBLzzaWA1YbH","type":"subjective","question":"Because plants turn solar light into food, every animal in a food chain depends ____ on the sun for its energy.","options":null,"answerIndex":null,"answer":"indirectly","explanation":["Carnivores do not absorb sunlight, but their food chain relies fundamentally on solar-powered producers."],"hint":"Think about how a lion eats an antelope, but the antelope ate grass that grew from sunlight.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"rJ1TXXBpWgL7Xw8Pt6UQ","type":"short","question":"Identify the odd one out in this group based on food chain roles: Moss, Fern, Grasshopper, Pine Tree.","options":null,"answerIndex":null,"answer":"Grasshopper","explanation":["Moss, fern, and pine tree are all photosynthetic producers, while a grasshopper is a consumer."],"hint":"Three of these make their own food, while one must eat to survive.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"ruf03MWkSrZztwH7wfuT","type":"polar","question":"Scavengers, like vultures, are consumers that feed on dead animals rather than hunting live prey.","options":["True","False"],"answerIndex":0,"answer":null,"explanation":["Scavengers consume animals that are already dead, helping to clean up the ecosystem alongside decomposers."],"hint":"Think about whether vultures hunt live animals or clean up remains.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"yyhdZVdXdTrxEawyP37h","type":"polar","question":"Plants are called producers because they produce their own food using sunlight.","options":["True","False"],"answerIndex":0,"answer":null,"explanation":["Producers, like green plants, manufacture their own nutrients via photosynthesis."],"hint":"Consider the definition of a producer in a food chain.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"},{"id":"zrZHJCPy63uYdBiokoq1","type":"objective","question":"Which of the following describes the correct order of energy transfer in a simple woodland food chain?","options":["Fox -> Rabbit -> Leaf","Leaf -> Fox -> Rabbit","Rabbit -> Leaf -> Fox","Leaf -> Rabbit -> Fox"],"answerIndex":3,"answer":null,"explanation":["Energy moves from the producer (Leaf) to the herbivore (Rabbit) and then to the carnivore (Fox)."],"hint":"Follow the energy path starting from the plant.","image":null,"video":"https://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1Vhttps://youtu.be/G1ODpDFRmlg?si=XnXzyEwmvgbaMr1V","videoScope":"set","topic":"General","classLevel":"primary5","scheme":"practice","subject":"science","subjectLabel":"Science","grade":"Primary 5"}];
